local oktools = {
    ["#Tool.advdupe2.name"] = true,
    ["#Tool.stacker.name"] = true
}

local function IsAdvDupe2Paste(pl)
    return AdvDupe2 and (
        AdvDupe2.SpawningEntity or
        (IsValid(pl) and pl.AdvDupe2 and (pl.AdvDupe2.Pasting or pl.AdvDupe2.Queued))
    )
end

local usergr = {
    ["User"] = 70,
    ["vip"] = 80,
    ["Premium"] = 100,

    ["d-moderator"] = 120,
    ["d-admin"] = 150,

    ["assistant"] = 180,
    ["mlmoder"] = 220,
    ["moder"] = 260,

    ["sponsor"] = 300,
    ["admin"] = 350,
    ["support"] = 400,

    ["d-arizona"] = 450,
    ["d-creator"] = 500,

    ["root"] = 600,
    ["overwatch"] = 650,

    ["zam-supervisior"] = 700,
    ["supervisior"] = 800,

    ["team"] = 900,
    ["uprav"] = 1200,
    ["*"] = 9999,
}

hook.Add('PlayerSpawnProp', 'PropLimit', function(pl)

    if IsAdvDupe2Paste(pl) then return true end

    local new = usergr[string.lower(pl:GetUserGroup())] or 70

    local donateLimit = 0

    if pl.DonatePropLimit and pl.DonatePropLimit ~= 0 then
        donateLimit = pl.DonatePropLimit
    end

    local kylLimit = 0

    if KylDonate and KylDonate.GetProps then
        kylLimit = KylDonate.GetProps(pl:SteamID64()) or 0
    end

    local totalLimit = new + donateLimit + kylLimit

    if pl:GetCount('props') >= totalLimit then
        rp.Notify(pl, NOTIFY_ERROR, 'Вы достигли лимита пропов!')
        return false
    end

    if (pl.cdnotify or 0) > CurTime() then return end

    pl.cdnotify = CurTime() + 1

    rp.Notify(
        pl,
        3,
        'Вы создали ' ..
        (pl:GetCount('props') + 1) ..
        '/' ..
        totalLimit ..
        ' пропов.'
    )
end)

hook('PlayerSpawnProp', 'pp.PlayerSpawnProp', function(pl, mdl)

    if IsAdvDupe2Paste(pl) then return true end

    if pl:IsRoot() then
        return true
    end

    if pl:IsBanned() then
        return false
    end

    local tool = pl:GetTool()

    if pl.lastPropSpawn and
        (pl.lastPropSpawn > CurTime() - .25) and
        ((tool == nil) or not oktools[tool.Name]) then

        rp.Notify(pl, NOTIFY_ERROR, term.Get('SpawnPropsSoFast'))

        if pl.failedPropAttempts and
            (pl.failedPropAttempts >= 5) and
            (pl.toldStaff ~= true) then

            ba.notify_staff(
                '# создал более 5 пропов в секунду. Не спускай глаз с него!',
                pl
            )

            pl.toldStaff = true
        end

        pl.lastPropSpawn = CurTime()
        pl.failedPropAttempts = (pl.failedPropAttempts or 0) + 1

        return false
    end

    pl.toldStaff = nil
    pl.failedPropAttempts = nil
    pl.lastPropSpawn = CurTime()

    if not table.HasValue(whitelistprops, mdl) then

        rp.Notify(pl, NOTIFY_ERROR, term.Get('PropNotWhitelisted'), mdl)

        local issuper = pl:IsSuperAdmin()

        if issuper then

            local pc_count = table.Count(rp.pp.ModelCache)

            if pc_count >= 100 then
                pl:Notify(NOTIFY_ERROR, term.Get('CacheFull'), pc_count)
                return false
            end

            rp.pp.ModelCache[mdl] = true
        end

        return issuper
    end
end)

local whitelistents = {
    ['gmod_trams_tatra_t3'] = true
}

local FindInSphere = ents.FindInSphere

hook('PlayerSpawnedProp', 'pp.PlayerSpawnedProp', function(pl, mdl, ent)

    ent:CPPISetOwner(pl)
    ent:SetNWEntity("PP_Owner", pl)
    ent:SetNWString("PP_Owner_Uid", pl:UniqueID())

    if IsAdvDupe2Paste(pl) then return end

    local gay_abuser = 0

    for k, v in ipairs(FindInSphere(ent:GetPos(), 8)) do
        if v:GetModel() == ent:GetModel() then
            gay_abuser = gay_abuser + 1
        end

        if gay_abuser >= 5 then
            v:Remove()
        end
    end

    ent:AddCallback('PhysicsCollide', function(ent, data)

        if data.HitEntity:IsWorld() then

            ent.physbuffer = (ent.physbuffer or 0) + 1

            if ent.physbuffer > 60 then
                rp.Notify(pl, 1, 'Такое запрещено')
                ent:Remove()
                return
            end
        end

        if data.HitEntity:IsPlayer() then

            local gay_abuser = 0

            for k, v in ipairs(FindInSphere(ent:GetPos(), 8)) do

                if v:GetModel() == ent:GetModel() then
                    gay_abuser = gay_abuser + 1
                end

                if gay_abuser >= 5 then
                    v:Remove()
                end
            end
        end
    end)

	local props = ent:IsConstrained() and
        constraint.GetAllConstrainedEntities(ent) or {}

    table.insert(props, ent)

    for _, prop in pairs(props) do

        local colliding = ents.FindInSphere(
            prop:LocalToWorld(prop:OBBCenter()),
            prop:BoundingRadius()
        )

        for k, v in pairs(colliding) do

            if not whitelistents[ent:GetClass()] and
                (v:IsVehicle() or v:IsPlayer() and v:GetObserverMode()) then

				if prop:NearestPoint(v:NearestPoint(prop:GetPos()))
                    :Distance(v:NearestPoint(prop:GetPos())) <= 20 then

					pl:SendLua(
                        "notification.AddLegacy('Вы не можете заморозить проп т.к он может застрять в игроке/машине!', NOTIFY_ERROR, 5)"
                    )

					ent:SetCollisionGroup(COLLISION_GROUP_WEAPON)

                    return false
				end
			else
				ent:SetCollisionGroup(COLLISION_GROUP_NONE)
            end
        end
    end
end)

